return {
    ["notice.label"] = "Notice:",
    ["notice.text"] = "These options may not take effect until the next relaunch of the game.",
    ["credits.label"] = "The following individuals have contributed to the Morrowind Script Extender:",
    ["logWarningsWithLuaStack.label"] = "Log warnings with lua stacktrace?",
    ["logWarningsWithLuaStack.description"] = "When enabled, any warnings raised during normal gameplay that would write to warnings.txt will also write to mwse.log. In addition, a stack trace is provided to give context to what mod may be responsible for the warning.\n\nThis can lead to superfluous log entries when using certain mods, like Better Bodies.",
    ["runInBackground.label"] = "Run Morrowind in the background?",
    ["runInBackground.description"] = "By default Morrowind skips most game logic when not in focus. When using windowed mode (including borderless fullscreen), this feature allows Morrowind to continue running. Enabling this can also help to increase stability, due to how Morrowind handles some audio threads.",
    ["playAudioInBackground.label"] = "Play audio in background?",
    ["playAudioInBackground.description"] = "By default, Morrowind does not use global audio playback, meaning that audio stops playing when the window is not in focus. Turning this on allows audio to work in the background.",
    ["letterboxMovies.label"] = "Letterbox movies?",
    ["letterboxMovies.description"] = "Morrowind stretches movies to fill the whole window by default. This option will instead render movies with black bars to either side, centering the movie in the window.",
    ["patchNiFlipController.label"] = "Fix NiFlipController cloning?",
    ["patchNiFlipController.description"] = "Morrowind incorrectly handles the affected map when cloning NiFlipController objects, preventing mods from using the controller for anything but the base map. MWSE fixes this issue. However, some mods contain bugged assets that have the incorrect affected map assigned, relying on the bug to reassign the controller back to the base map. Disabling this fix will provide support for these mods, but will also prevent newer mods from taking advantage of the fixed controller.\n\nIt is recommended that you leave this enabled unless you know you need the compatibility.",
    ["keepAllNetImmerseObjectsAlive.label"] = "Cache all NetImmerse lua objects?",
    ["keepAllNetImmerseObjectsAlive.description"] = "WARNING: Only used for debugging purposes. Enabling this without knowing what you're doing WILL lead to memory leaks.\n\nWhen enabled, NetImmerse objects will use the same lua object caching system that TES3 objects use, allowing them to be string-compared or used as table keys.",
    ["enableLegacyLuaMods.label"] = "Enable legacy lua mods?",
    ["enableLegacyLuaMods.description"] = "If enabled, early alpha lua mods will be supported\n\nLegacy lua mods can be found in:\nData Files\\MWSE\\lua folder.",
    ["enableLogColors.label"] = "Enable Log Colors",
    ["enableLogColors.description"] = "If enabled, mwseLogger logging messages will be color-coded based on the severity of the message. However, this will make the MWSE.log file more difficult to read in a text editor.",
    ["enableLogLineNumbers.label"] = "Enable Log Line Numbers",
    ["enableLogLineNumbers.description"] = "If enabled, line numbers will be included in logging messages generated by mwseLoggers. This does come with a slight performance cost, but it is unlikely to be very noticeable. Line numbers are only computed if the logging level is high enough to print the log message.",
    ["enableDependencyChecks.label"] = "Enable Dependency Checks",
    ["enableDependencyChecks.description"] = "If enabled, MWSE will check for dependencies of mods and warn the user if they are missing.",
    ["replaceDialogueFiltering.label"] = "Replace Dialogue Filtering",
    ["replaceDialogueFiltering.description"] = "If enabled, MWSE will replace the logic for dialogue filtering. This feature is currently in public testing.",
    ["enableLuaErrorNotifications.label"] = "Enable lua error notifications",
    ["enableLuaErrorNotifications.description"] = "If enabled, notification pop-ups will appear when a lua error is logged. They contain the mod name and a short error description only. Many released mods cause frequent non-critical errors, so this mode is primarily intended for use in development and bugfixing.",
    ["useSkinnedAccurateActivationRaytests.label"] = "Enable skinned-accurate activation raytests",
    ["useSkinnedAccurateActivationRaytests.description"] = "If enabled, the player activation target raytest will be more accurate around skinned actors. This may impose a performance penalty in very complex situations.",
    ["suppressUselessWarnings.label"] = "Suppress useless game warnings?",
    ["suppressUselessWarnings.description"] = "If enabled, the initial startup warning about mismatched masters is suppressed. This warning is almost always displayed on any modded install, and often prompts users to click Yes to All, hiding actually helpful warnings.",
    ["replaceLightSorting.label"] = "Replace light sorting?",
    ["replaceLightSorting.description"] = "If enabled, the default method of prioritizing lights that affect a mesh is replaced with a new method. This greatly reduces the amount of landscape seams as well as the amount of light popping, but may diminish the impact of carried torches in some environments.",

    -- Masked Software Occlusion Culling page.
    ["msoc.pageLabel"] = "Occlusion Culling",
    ["msoc.mainCategory.label"] = "Main",
    ["msoc.occluderCategory.label"] = "Occluder selection",
    ["msoc.occludeeCategory.label"] = "Occludee / query",
    ["msoc.threadpoolCategory.label"] = "Async threadpool",
    ["msoc.debugCategory.label"] = "Debug tinting",
    ["msoc.sidebarInfo.label"] = "Masked Software Occlusion Culling",
    ["msoc.sidebarInfo.text"] = "Intel's software occluder-rasterisation pass, wedged between the engine's frustum test and its Display call. Large opaque meshes are rasterised into a low-resolution depth buffer; every other mesh is queried against that buffer and culled when fully hidden.\n\nAll distance and size values are in Morrowind world units (1 unit ~= 1.4 cm). Changes take effect on the next frame; no restart required.",

    ["enableMSOC.label"] = "Enable occlusion culling?",
    ["enableMSOC.description"] = "Master switch for the Masked Software Occlusion Culling pass. When disabled, the scene graph traversal falls back to the engine's original frustum-only path.\n\nDisabling at runtime stops occluder rasterisation and visibility queries the next frame, but the CullShow detour remains installed. Toggling only after changing occluder/occludee gates is fine.",
    ["occlusionEnableInterior.label"] = "Enable in interiors?",
    ["occlusionEnableInterior.description"] = "Run the MSOC pass when the player is inside an interior cell. Interior scenes with lots of walls and doors (Vivec cantons, tombs, Dwemer ruins) are the highest-benefit case for occlusion culling.",
    ["occlusionEnableExterior.label"] = "Enable in exteriors?",
    ["occlusionEnableExterior.description"] = "Run the MSOC pass in exterior cells. Open-world scenes with dense architecture (Balmora, Vivec exterior) benefit most; sparse wilderness may see little gain and can be safely disabled here without affecting interiors.",
    ["occlusionSkipTerrainOccludees.label"] = "Skip terrain occludee queries?",
    ["occlusionSkipTerrainOccludees.description"] = "Landscape patches (25 verts / 32 tris, arranged 4x4 per cell under the engine's WorldLandscape root) sit directly under the camera and are visible from nearly every viewpoint. When enabled, these patches bypass the MSOC visibility test and render unconditionally, saving one TestRect call and depth-buffer lookups per patch per frame.\n\nDisable only to A/B test the skip's impact — the culler can legitimately occlude a terrain patch that's fully behind a wall, but such cases are rare and the saved query cost normally outweighs them.\n\nDefault: on.",
    ["occlusionAggregateTerrain.label"] = "Aggregate terrain as occluder?",
    ["occlusionAggregateTerrain.description"] = "When enabled, the 16 subcell patches of each visible Land are merged into a single combined occluder and rasterised in one submission. Individual patches (25 verts / 32 tris) almost always fail the thin-axis gate and contribute no occlusion; merging produces the hill/horizon silhouette that actually occludes architecture behind slopes and ridges.\n\nThis runs before the main scene traversal so terrain is in the depth buffer before non-terrain leaves are tested. Submission count scales with visible Lands (~9 in a 3x3 view); each submission is ~16 × 32 = 512 triangles.\n\nMost beneficial in highland areas (Red Mountain approach, Sheogorad peaks) where the terrain silhouette can cull whole building clusters. Safe to disable on flat-terrain profiles (Ascadian Isles plains) where there's no silhouette to rasterise — the per-frame merge still costs a few hundred triangle submissions for no occlusion gain.\n\nDefault: on.",
    ["occlusionCullLights.label"] = "Cull occluded lights?",
    ["occlusionCullLights.description"] = "When enabled, every registered NiLight is tested once per frame against the MSOC depth buffer using its inherited world-bound sphere. If the sphere is fully occluded, the light is temporarily disabled for that frame — it still exists in the scene graph, but the D3D8 renderer's per-draw updateLights pass treats it as if its enabled flag were cleared. Lights in view but with their entire sphere of influence behind a wall are the main beneficiary: Vivec cantons, tomb interiors, and plaza lamp rows where dozens of static fixtures sit behind opaque architecture.\n\nMorrowind submits every enabled NiLight to D3D regardless of how many there are; when the total exceeds D3D's MaxActiveLights the driver drops the excess non-deterministically. Culling occluded ones first makes the selection deterministic — visible lights stay lit even in dense scenes. A configurable hysteresis (see 'Light cull hysteresis frames') is applied to prevent flicker at occlusion boundaries.\n\nDisable if you see lights popping on/off incorrectly, or if you're profiling and the per-frame light sphere test is non-trivially expensive (it runs over every live NiLight, so scenes with hundreds can cost more than they save).\n\nDefault: on.",
    ["occlusionLightCullHysteresisFrames.label"] = "Light cull hysteresis frames",
    ["occlusionLightCullHysteresisFrames.description"] = "Number of consecutive frames a light's world-bound sphere must be reported OCCLUDED before it latches into the 'culled' state. Visible verdicts unlatch immediately (the light pops back on the same frame it re-enters view), so this only tunes the off-transition.\n\nLower values react faster to things like a door closing in front of a lamp but risk flicker on transient misfires (e.g. a single-frame false positive from sub-pixel geometry). Higher values smooth out flicker at the cost of keeping an already-hidden light in the D3D submission list for up to N extra frames.\n\n0 or 1 = no hysteresis (latch on first occluded frame). 3 ≈ 50 ms at 60 FPS. 10 ≈ 170 ms. The internal counter caps at 255, so values above that disable the latch entirely.\n\nDefault: 3.",
    ["occlusionTemporalCoherenceFrames.label"] = "Temporal coherence frames",
    ["occlusionTemporalCoherenceFrames.description"] = "Number of frames to reuse a deferred shape's visibility verdict before re-querying. 0 disables the cache (every visible deferred shape is re-tested every frame). Higher values skip more TestRect calls in the drain loop, trading up to N frames of latency on occluder→visible transitions (a shape that becomes visible mid-interval stays hidden until the next re-query).\n\nEntries are invalidated immediately if the shape moves (worldBoundOrigin or radius changes), so animated creatures, flickering lights, and physics-driven objects always re-query. Only static geometry benefits from reuse.\n\nTypical gains: N=2 halves drain cost with barely visible pops on fast camera turns; N=5 is more aggressive and noticeable; N=10 is for stress testing.\n\nDefault: 0.",

    ["occlusionOccluderRadiusMin.label"] = "Occluder min radius",
    ["occlusionOccluderRadiusMin.description"] = "Minimum world-bound sphere radius for a mesh to be considered as an occluder. Below this, rasterising the mesh wastes more time than it saves.\n\nDefault: 256. Lower values catch more small occluders (clutter, crates) but raise per-frame rasterisation cost; higher values keep only large architecture but miss shadowing contributions from medium props.",
    ["occlusionOccluderRadiusMax.label"] = "Occluder max radius",
    ["occlusionOccluderRadiusMax.description"] = "Maximum world-bound sphere radius for a mesh to qualify as an occluder. Meshes above this (terrain patches, skydomes, sky domes, whole-cell hulls) are skipped — they typically cover most of the screen from any viewpoint and rasterising them hurts more than it helps.\n\nDefault: 4096.",
    ["occlusionOccluderMinDimension.label"] = "Occluder min thin-axis dimension",
    ["occlusionOccluderMinDimension.description"] = "A mesh is rejected as an occluder if two or more of its world-AABB axes are shorter than this value. Pencil-shaped meshes (railings, poles, flagpoles) have silhouettes too small to contribute useful occlusion and are filtered out early.\n\nDefault: 128. Walls and floors, which are thin on only one axis, still qualify.",
    ["occlusionOccluderMaxTriangles.label"] = "Occluder max triangles",
    ["occlusionOccluderMaxTriangles.description"] = "Upper bound on triangle count for an occluder. Rasterisation cost scales linearly with triangles, so very dense meshes cost more than they pay back in occlusion.\n\nDefault: 4096. Lower to cap cost in triangle-heavy cells; raise only if profiling shows occluder quality is the bottleneck.",
    ["occlusionInsideOccluderMargin.label"] = "Inside-occluder safety margin",
    ["occlusionInsideOccluderMargin.description"] = "Slack added to a candidate occluder's world AABB when testing whether the camera sits inside it. If the camera is within this margin of the tight AABB, the mesh is skipped as an occluder for this frame — rasterising a mesh the camera is inside would falsely occlude everything behind it.\n\nDefault: 64.",

    ["occlusionDepthSlackWorldUnits.label"] = "Occludee depth slack",
    ["occlusionDepthSlackWorldUnits.description"] = "Extra world-space distance added to an occludee's near-surface estimate before the MSOC TestRect call. This biases the query toward declaring the mesh visible, preventing flicker when a mesh sits nearly flush with an occluder.\n\nDefault: 128. Raise if you see shapes popping in and out behind their own walls; lower if false-positives let too much through.",
    ["occlusionOccludeeMinRadius.label"] = "Occludee min radius",
    ["occlusionOccludeeMinRadius.description"] = "Queries are skipped for shapes whose world-bound sphere radius is below this value — their NDC footprint is too small for the hierarchical depth buffer to decide reliably, and the test cost exceeds any cull benefit.\n\nDefault: 1. Small leaves still render normally; they just bypass the occlusion test.",

    ["occlusionAsyncOccluders.label"] = "Async occluder rasterisation?",
    ["occlusionAsyncOccluders.description"] = "When enabled, occluder triangles are submitted to an Intel CullingThreadpool and rasterised on worker threads instead of inline on the cull-pass thread. The main thread continues traversing the scene graph while occluders are being drawn in parallel; a Flush barrier runs before the visibility drain to guarantee the depth buffer is complete.\n\nEnable when rasterise cost dominates drain cost in the MWSE.log MSOC metrics (rasterizeUs > drainUs). Disable on single-core or low-thread-count systems — waking and suspending workers each frame has overhead that won't amortise. Default: off.",
    ["occlusionThreadpoolThreadCount.label"] = "Threadpool worker count",
    ["occlusionThreadpoolThreadCount.description"] = "Number of worker threads the threadpool uses to rasterise occluders. Only consulted when Async occluder rasterisation is enabled. 0 means auto — max(hardware_concurrency - 2, 1), leaving one full core for the main thread. Default: 0.\n\nSet manually if you know your core count and want to reserve more/fewer threads for other work.\n\nNote: thread count cannot exceed BinsW × BinsH or the threadpool will crash. The MCM clamps the slider to that product on every change (here and on either bins slider) as a guard, but if you bypass the MCM and edit MWSE.json directly, make sure the value stays within bounds.",
    ["occlusionThreadpoolBinsW.label"] = "Threadpool bins (width)",
    ["occlusionThreadpoolBinsW.description"] = "The screen is divided into BinsW × BinsH rectangular bins for load balancing across worker threads. Total bins should be at least equal to the worker count. Default: 4.",
    ["occlusionThreadpoolBinsH.label"] = "Threadpool bins (height)",
    ["occlusionThreadpoolBinsH.description"] = "The screen is divided into BinsW × BinsH rectangular bins for load balancing across worker threads. Total bins should be at least equal to the worker count. Default: 2.",

    ["debugOcclusionTintOccluder.label"] = "Tint occluders yellow",
    ["debugOcclusionTintOccluder.description"] = "Overlays a yellow emissive tint on every mesh rasterised into the depth buffer as an occluder. Use to check which meshes qualify under the current Occluder settings.",
    ["debugOcclusionTintOccluded.label"] = "Tint occluded shapes red",
    ["debugOcclusionTintOccluded.description"] = "Keeps shapes that failed the MSOC visibility test visible and tints them red. Use to verify the culler is rejecting the right meshes; production use should leave this off (culled meshes are invisible by default).",
    ["debugOcclusionTintTested.label"] = "Tint visible occludees green",
    ["debugOcclusionTintTested.description"] = "Tints every mesh that passed the MSOC visibility test green. Combined with the red and yellow tints, gives a full visual classification of the frame's occlusion decisions.",
    ["occlusionLogPerFrame.label"] = "Log per-frame culling events",
    ["occlusionLogPerFrame.description"] = "Writes one MWSE.log line per frame that produced at least one OCCLUDED verdict. Useful for verifying the culler is firing in a specific scene. Verbose — leave off unless investigating.\n\nDefault: off.",
    ["occlusionLogAggregate.label"] = "Log periodic aggregate stats",
    ["occlusionLogAggregate.description"] = "Writes one MWSE.log line every 300 frames with cumulative culler counters (rasterised, queryOccluded/Tested, viewCulled, drain timings). Useful for steady-state profiling.\n\nDefault: off."
}
